#!/usr/bin/env node
const { Command } = require('commander');
const program = new Command();

program
  .name('askelira')
  .description('Visual swarm intelligence for developers')
  .version('2.0.0');

program
  .command('start')
  .description('Start AskElira gateway')
  .action(require('../src/cli/start'));

program
  .command('swarm')
  .option('-q, --question <text>', 'Question for agents')
  .option('-a, --agents <number>', 'Agent count (1k-1M)', '10000')
  .action(require('../src/cli/swarm'));

program.parse();

Make executable: chmod +x bin/cli.js

