const { Gateway } = require('../gateway');
const chalk = require('chalk');

module.exports = async function start() {
  console.log(chalk.cyan('🚀 Starting AskElira...'));

  // Check if OpenClaw installed
  const hasOpenClaw = await checkOpenClaw();

  if (!hasOpenClaw) {
    console.log('Installing OpenClaw...');
    await installOpenClaw();
  }

  // Start gateway
  const gateway = new Gateway();
  await gateway.start();

  console.log(chalk.green('✅ AskElira ready!'));
  console.log('Try: askelira swarm --question "Should I quit my job?"');
};

async function checkOpenClaw() {
  try {
    require('openclaw');
    return true;
  } catch {
    return false;
  }
}

async function installOpenClaw() {
  const { execSync } = require('child_process');
  execSync('npm install -g openclaw', { stdio: 'inherit' });
}

Create src/cli/swarm.js - Swarm command handler:

const { Swarm } = require('../agents/swarm');
const { saveToMemory } = require('../memory');
const chalk = require('chalk');

module.exports = async function swarm(options) {
  const { question, agents } = options;

  if (!question) {
    console.error('Error: --question required');
    process.exit(1);
  }

  const agentCount = parseInt(agents);
  const cost = calculateCost(agentCount);

  console.log(chalk.cyan(`\n🧠 Starting ${agentCount.toLocaleString()} agent swarm...`));
  console.log(chalk.gray(`   Cost: $${cost.toFixed(3)}`));
  console.log();

  const swarm = new Swarm({ agents: agentCount });
  const result = await swarm.debate(question);

  // Save to memory
  await saveToMemory(result);

  // Display results
  console.log(chalk.green(`\n✅ Decision: ${result.decision}`));
  console.log(chalk.blue(`   Confidence: ${result.confidence}%`));
  console.log(chalk.gray(`   Cost: $${result.actualCost.toFixed(3)}`));

  return result;
};

function calculateCost(agents) {
  return agents * 0.000007; // ~$0.007 per 1k agents
}

Create src/gateway/index.js - OpenClaw gateway wrapper:

const { spawn } = require('child_process');
const chalk = require('chalk');

class Gateway {
  constructor() {
    this.process = null;
    this.port = 5678;
  }

  async start() {
    // Check if already running
    const running = await this.isRunning();
    if (running) {
      console.log(chalk.green('✅ Gateway already running'));
      return;
    }

    // Start OpenClaw gateway
    this.process = spawn('openclaw', ['gateway', 'start'], {
      stdio: 'inherit'
    });

    // Wait for ready
    await this.waitForReady();
  }

  async isRunning() {
    try {
      const res = await fetch(`http://localhost:${this.port}/health`);
      return res.ok;
    } catch {
      return false;
    }
  }

  async waitForReady() {
    for (let i = 0; i < 30; i++) {
      if (await this.isRunning()) return;
      await new Promise(r => setTimeout(r, 1000));
    }
    throw new Error('Gateway failed to start');
  }
}

module.exports = { Gateway };

Create src/agents/swarm.js - Core swarm orchestration:

const { Alba } = require('./alba');
const { David } = require('./david');
const { Vex } = require('./vex');
const { Elira } = require('./elira');

class Swarm {
  constructor(options = {}) {
    this.agents = options.agents || 10000;
    this.question = null;
  }

  async debate(question) {
    this.question = question;

    // Alba: Research
    const research = await new Alba().research(question);

    // David: Swarm debate
    const debate = await new David(this.agents).run(question, research);

    // Vex: Audit
    const audit = await new Vex().validate(debate);

    // Elira: Synthesize
    const result = await new Elira().synthesize({
      question,
      research,
      debate,
      audit
    });

    return {
      decision: result.decision,
      confidence: result.confidence,
      argumentsFor: result.for,
      argumentsAgainst: result.against,
      actualCost: result.cost,
      agents: this.agents,
      timestamp: new Date().toISOString()
    };
  }
}

module.exports = { Swarm };

Create src/memory/index.js - Hybrid memory system:

const fs = require('fs');
const path = require('path');
const { ChromaClient } = require('chromadb');

const MEMORY_DIR = path.join(process.env.HOME, '.askelira', 'memory');
const VECTOR_DIR = path.join(MEMORY_DIR, 'vectordb');

// Ensure directories exist
fs.mkdirSync(MEMORY_DIR, { recursive: true });
fs.mkdirSync(VECTOR_DIR, { recursive: true });

const chroma = new ChromaClient({ path: VECTOR_DIR });
let collection;

async function init() {
  collection = await chroma.getOrCreateCollection({ name: 'debates' });
}

async function saveToMemory(result) {
  const date = new Date().toISOString().split('T')[0];
  const filepath = path.join(MEMORY_DIR, `${date}.md`);

  // Save to file (transparency)
  const entry = `
## ${result.question}
**Decision:** ${result.decision} (${result.confidence}%)
**Time:** ${new Date().toLocaleTimeString()}
**Cost:** $${result.actualCost.toFixed(3)}
**Agents:** ${result.agents.toLocaleString()}

### Arguments FOR:
${result.argumentsFor.map(a => `- ${a}`).join('\n')}

### Arguments AGAINST:
${result.argumentsAgainst.map(a => `- ${a}`).join('\n')}
`;

  fs.appendFileSync(filepath, entry);

  // Save to vector DB (semantic search)
  if (!collection) await init();

  await collection.add({
    ids: [`debate-${Date.now()}`],
    documents: [result.question],
    metadatas: [{
      decision: result.decision,
      confidence: result.confidence,
      date
    }]
  });
}

module.exports = { saveToMemory, init };

